class AbstractAgent(Generic[AgentDepsT, OutputDataT], ABC):
    @property
    @abstractmethod
    def model(self) -> models.Model | models.KnownModelName | str | None:
        """默认模型配置"""

    @property
    @abstractmethod
    def name(self) -> str | None:
        """代理名称，用于日志记录"""

    async def run(self, user_prompt: str | Sequence[UserContent] | None = None, **kwargs) -> AgentRunResult[OutputDataT]:
        """异步运行代理"""

    def run_sync(self, user_prompt: str | Sequence[UserContent] | None = None, **kwargs) -> AgentRunResult[Any]:
        """同步运行代理"""

class ModelMessage(BaseModel):
    """模型消息基类"""

class TextPart(ModelRequestPart):
    content: str

class ToolCallPart(BaseToolCallPart):
    tool_name: str
    tool_call_id: str
    arguments: dict[str, Any]

class FinalResultEvent(AgentStreamEvent):
    tool_name: str | None
    tool_call_id: str | None
